# CFD scoring - Doench 2016 mismatch penalty matrix (position- and substitution-specific).
# Encoded here as the published values (rNt:dNt pairs, position 1-20). Source: Doench Nat Biotechnol 2016 Suppl.
# This is the standard CFD_scoring mismatch dict used by the Broad sgRNA Designer / CRISPOR.
# We'll fetch the canonical pickle values from CRISPOR's published table to avoid transcription error.
import urllib.request, json, os
# CRISPOR ships cfd score matrices; the values are also in the azimuth/CFD repo. Try to fetch.
urls = {
 'mm':'https://raw.githubusercontent.com/maximilianh/crisporWebsite/master/bin/src/cfd-score-calculator/mismatch_score.pkl',
 'pam':'https://raw.githubusercontent.com/maximilianh/crisporWebsite/master/bin/src/cfd-score-calculator/pam_scores.pkl'
}
for k,u in urls.items():
    try:
        urllib.request.urlretrieve(u, f'/tmp/cfd_{k}.pkl')
        print(k, "ok", os.path.getsize(f'/tmp/cfd_{k}.pkl'), "bytes")
    except Exception as e:
        print(k, "FAILED", e)

