cd /tmp/genome && echo "Extracting CDS and exon intervals per chromosome..."
# Keep only CDS (coding) and exon features; output: chrom,start,end,gene_name,biotype,feature
zcat annot.gtf.gz | awk -F'\t' '$3=="CDS" || $3=="exon" {
  match($9, /gene_name "([^"]+)"/, gn);
  match($9, /gene_biotype "([^"]+)"/, gb);
  print $1"\t"$4"\t"$5"\t"gn[1]"\t"gb[1]"\t"$3
}' > features.bed
wc -l features.bed
echo "--- CDS vs exon counts ---"
cut -f6 features.bed | sort | uniq -c
head -3 features.bed

